//! Strict deterministic baseline metrics over the frozen Phase-2C closed-trade ledger.
use std::{fs, path::{Path,PathBuf}};
use arrow_array::{Array,Float64Array,StringArray,UInt64Array};
use arrow_schema::DataType;
use parquet::arrow::arrow_reader::ParquetRecordBatchReaderBuilder;
use serde::Serialize;
use serde_json::{json,Map,Value};
use sha2::{Digest,Sha256};

pub type Result<T>=std::result::Result<T,String>;
const COLUMNS:[(&str,DataType);10]=[("trade_id",DataType::UInt64),("side",DataType::Utf8),("entry_timestamp",DataType::Utf8),("exit_timestamp",DataType::Utf8),("entry_index",DataType::UInt64),("exit_index",DataType::UInt64),("entry_price",DataType::Float64),("exit_price",DataType::Float64),("bars_held",DataType::UInt64),("gross_pnl_per_unit",DataType::Float64)];
#[derive(Clone)] struct Trade{id:u64,side:String,entry_timestamp:String,exit_timestamp:String,entry_index:u64,exit_index:u64,entry_price:f64,exit_price:f64,bars_held:u64,pnl:f64}
#[derive(Clone,Serialize)] pub struct Metrics{pub metrics_version:&'static str,pub trade_count:u64,pub win_count:u64,pub loss_count:u64,pub breakeven_count:u64,pub gross_profit:f64,pub gross_loss_abs:f64,pub net_gross_pnl:f64,pub average_trade:Option<f64>,pub win_rate:Option<f64>,pub average_win:Option<f64>,pub average_loss_abs:Option<f64>,pub profit_factor:Option<f64>}
fn only(o:&Map<String,Value>)->Result<()> {for k in o.keys(){if !["task_version","task_type","input_path","output_path"].contains(&k.as_str()){return Err(format!("unknown metrics task field {k:?}"))}}Ok(())}
fn string(o:&Map<String,Value>,k:&str)->Result<String>{o.get(k).and_then(Value::as_str).filter(|x|!x.trim().is_empty()).map(str::to_owned).ok_or_else(||format!("missing or invalid metrics task field {k}"))}
fn input(raw:&str)->Result<PathBuf>{let p=PathBuf::from(raw);if raw.trim().is_empty()||!p.is_file(){Err("metrics input_path is not a readable regular file".into())}else{Ok(p)}}
fn output(raw:&str)->Result<PathBuf>{let p=PathBuf::from(raw);if raw.trim().is_empty()||p.exists()||p.parent().map_or(true,|x|!x.is_dir()){Err("metrics output_path must not exist and its parent must exist".into())}else{Ok(p)}}
fn read(path:&Path)->Result<Vec<Trade>>{let builder=ParquetRecordBatchReaderBuilder::try_new(fs::File::open(path).map_err(|e|format!("open closed-trade ledger: {e}"))?).map_err(|e|format!("read closed-trade ledger: {e}"))?;let schema=builder.schema();if schema.fields().len()!=COLUMNS.len(){return Err("closed-trade ledger schema must contain exactly the frozen columns".into())}for(i,(name,ty))in COLUMNS.iter().enumerate(){let field=schema.field(i);if field.name()!=*name||field.data_type()!=ty{return Err(format!("closed-trade ledger schema mismatch for {name}"))}}let mut rows=Vec::new();for batch in builder.build().map_err(|e|e.to_string())?{let batch=batch.map_err(|e|e.to_string())?;let ids=batch.column(0).as_any().downcast_ref::<UInt64Array>().ok_or("closed-trade ledger trade_id type invalid")?;let sides=batch.column(1).as_any().downcast_ref::<StringArray>().ok_or("closed-trade ledger side type invalid")?;let entries=batch.column(2).as_any().downcast_ref::<StringArray>().ok_or("closed-trade ledger entry_timestamp type invalid")?;let exits=batch.column(3).as_any().downcast_ref::<StringArray>().ok_or("closed-trade ledger exit_timestamp type invalid")?;let entry_indices=batch.column(4).as_any().downcast_ref::<UInt64Array>().ok_or("closed-trade ledger entry_index type invalid")?;let exit_indices=batch.column(5).as_any().downcast_ref::<UInt64Array>().ok_or("closed-trade ledger exit_index type invalid")?;let entry_prices=batch.column(6).as_any().downcast_ref::<Float64Array>().ok_or("closed-trade ledger entry_price type invalid")?;let exit_prices=batch.column(7).as_any().downcast_ref::<Float64Array>().ok_or("closed-trade ledger exit_price type invalid")?;let held=batch.column(8).as_any().downcast_ref::<UInt64Array>().ok_or("closed-trade ledger bars_held type invalid")?;let pnls=batch.column(9).as_any().downcast_ref::<Float64Array>().ok_or("closed-trade ledger gross_pnl_per_unit type invalid")?;for i in 0..batch.num_rows(){if [ids.is_null(i),sides.is_null(i),entries.is_null(i),exits.is_null(i),entry_indices.is_null(i),exit_indices.is_null(i),entry_prices.is_null(i),exit_prices.is_null(i),held.is_null(i),pnls.is_null(i)].into_iter().any(|x|x){return Err("closed-trade ledger required values must not be null".into())}let id=ids.value(i);if id!=rows.len()as u64+1{return Err("closed-trade ledger trade_id must be sequential beginning at 1".into())}let side=sides.value(i);if side!="long"&&side!="short"{return Err("closed-trade ledger side must be long or short".into())}let(ep,xp,pnl)=(entry_prices.value(i),exit_prices.value(i),pnls.value(i));if !ep.is_finite()||!xp.is_finite()||!pnl.is_finite(){return Err("closed-trade ledger prices and P&L must be finite".into())}let(a,b,h)=(entry_indices.value(i),exit_indices.value(i),held.value(i));if b<=a{return Err("closed-trade ledger exit_index must be greater than entry_index".into())}if h!=b-a{return Err("closed-trade ledger bars_held must equal exit_index minus entry_index".into())}rows.push(Trade{id,side:side.into(),entry_timestamp:entries.value(i).into(),exit_timestamp:exits.value(i).into(),entry_index:a,exit_index:b,entry_price:ep,exit_price:xp,bars_held:h,pnl})}}Ok(rows)}
fn metrics(rows:&[Trade])->Metrics{let(mut wins,mut losses,mut breakeven,mut profit,mut loss,mut net)=(0u64,0u64,0u64,0.,0.,0.);for row in rows{net+=row.pnl;if row.pnl>0.{wins+=1;profit+=row.pnl}else if row.pnl<0.{losses+=1;loss-=row.pnl}else{breakeven+=1}}let n=rows.len()as u64;Metrics{metrics_version:"closed_trade_metrics_v1",trade_count:n,win_count:wins,loss_count:losses,breakeven_count:breakeven,gross_profit:profit,gross_loss_abs:loss,net_gross_pnl:net,average_trade:(n>0).then(||net/n as f64),win_rate:(n>0).then(||wins as f64/n as f64),average_win:(wins>0).then(||profit/wins as f64),average_loss_abs:(losses>0).then(||loss/losses as f64),profit_factor:(losses>0).then(||profit/loss)}}
fn identity(rows:&[Trade],metrics:&Metrics)->String{let mut h=Sha256::new();h.update(b"nora.metrics.closed_trades_v1.semantic.v1\0");h.update(b"phase2c.closed_trade_ledger.schema.v1\0");for row in rows{h.update(row.id.to_be_bytes());h.update(row.side.as_bytes());h.update([0]);h.update(row.entry_timestamp.as_bytes());h.update([0]);h.update(row.exit_timestamp.as_bytes());h.update([0]);h.update(row.entry_index.to_be_bytes());h.update(row.exit_index.to_be_bytes());h.update(row.entry_price.to_bits().to_be_bytes());h.update(row.exit_price.to_bits().to_be_bytes());h.update(row.bars_held.to_be_bytes());h.update(row.pnl.to_bits().to_be_bytes())}h.update(serde_json::to_string(metrics).unwrap().as_bytes());format!("{:x}",h.finalize())}
pub fn task(o:&Map<String,Value>)->Result<Value>{only(o)?;if o.get("task_version").and_then(Value::as_u64)!=Some(1){return Err("unsupported task_version; expected 1".into())}if o.get("task_type").and_then(Value::as_str)!=Some("compute_closed_trade_metrics_v1"){return Err("invalid metrics task_type".into())}let source=input(&string(o,"input_path")?)?;let dst=output(&string(o,"output_path")?)?;let resolved_output=dst.parent().unwrap().canonicalize().map_err(|e|format!("resolve metrics output_path: {e}"))?.join(dst.file_name().unwrap());let resolved_input=source.canonicalize().map_err(|e|format!("resolve metrics input_path: {e}"))?;if resolved_input==resolved_output{return Err("metrics input_path and output_path must differ".into())}let rows=read(&source)?;let calculated=metrics(&rows);let id=identity(&rows,&calculated);let canonical=serde_json::to_string(&calculated).map_err(|e|e.to_string())?;let tmp=dst.with_file_name(format!(".{}.{}.partial",dst.file_name().and_then(|x|x.to_str()).ok_or("malformed metrics output_path")?,std::process::id()));if let Err(e)=fs::write(&tmp,canonical){let _=fs::remove_file(&tmp);return Err(format!("write metrics temporary artifact: {e}"))}if let Err(e)=fs::rename(&tmp,&dst){let _=fs::remove_file(&tmp);return Err(format!("atomic publish metrics artifact: {e}"))}Ok(json!({"ok":true,"task_type":"compute_closed_trade_metrics_v1","input_row_count":rows.len(),"output_path":dst,"metrics":calculated,"metrics_semantic_identity":id}))}
